# Geometry module providing shapes and utilities

class Measurable:
    @abstract
    def measure(self) -> float:
        ...

    @abstract
    def describe(self) -> str:
        ...

class Rectangle(Measurable):
    width: float
    height: float

    def __init__(self, w: float, h: float):
        self.width = w
        self.height = h

    @override
    def measure(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return "Rectangle"

class Circle(Measurable):
    radius: float

    def __init__(self, r: float):
        self.radius = r

    @override
    def measure(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def describe(self) -> str:
        return "Circle"

def calculate_total_area(shapes: list[Measurable]) -> float:
    total: float = 0.0
    for shape in shapes:
        total = total + shape.measure()
    return total

def format_measurement(m: Measurable) -> str:
    desc: str = m.describe()
    area: float = m.measure()
    return desc + ": " + str(area)

class Measurement:
    name: str
    value: float

    def __init__(self, n: str, v: float):
        self.name = n
        self.value = v
